const doc = $json.found;
const fields = doc.fields;

// Extract addresses safely
const addressesRaw = fields.addresses?.arrayValue?.values || [];

const addresses = addressesRaw.map((addr, index) => {
  const f = addr.mapValue.fields;

  const line1 = f.line1?.stringValue || "";
  const line2 = f.line2?.stringValue || "";
  const landmark = f.landmark?.stringValue || "";
  const city = f.city?.stringValue || "";
  const pincode = f.pincode?.stringValue || "";
  const latitude = f.location?.geoPointValue?.latitude || null;
  const longitude = f.location?.geoPointValue?.longitude || null;

  return {
    address_index: index,
    line_1: line1,
    line_2: line2,
    landmark: landmark,
    city: city,
    pincode: pincode,
    location: {
      latitude,
      longitude
    },
    full_address: [
      line1,
      line2,
      landmark,
      city && pincode ? `${city} - ${pincode}` : city
    ]
      .filter(Boolean)
      .join(", ")
  };
});

// Extract service references as IDs
const extractRefs = (arr) =>
  (arr?.values || []).map(v =>
    v.referenceValue.split('/').pop()
  );

const services = fields.services?.mapValue?.fields || {};

return [{
  profile : {
    id: doc.name.split('/').pop(),
    name: fields.name?.stringValue || "",
    email: fields.email?.stringValue || "",
    phone: fields.phone?.stringValue || "",
    addresses,
    services: {
      requested: extractRefs(services.requested?.arrayValue),
      scheduled: extractRefs(services.scheduled?.arrayValue),
      completed: extractRefs(services.completed?.arrayValue),
      cancelled: extractRefs(services.cancelled?.arrayValue),
    }
  }
}];

const doc = $json.found;
const fields = doc.fields;

// ---------- Extract address (city + pincode + location + full_address) ----------
const addressFields = fields.address?.mapValue?.fields || {};

const city = addressFields.city?.stringValue || "";
const pincode = addressFields.pincode?.stringValue || "";
const latitude = addressFields.location?.geoPointValue?.latitude || null;
const longitude = addressFields.location?.geoPointValue?.longitude || null;

const address = {
  city,
  pincode,
  location: {
    latitude,
    longitude
  },
  full_address: city && pincode
    ? `${city} - ${pincode}`
    : city
};

// ---------- Extract job references ----------
const extractRefs = (arr) =>
  (arr?.values || []).map(v =>
    v.referenceValue.split('/').pop()
  );

const jobsRaw = fields.jobs?.mapValue?.fields || {};

const jobs = {
  applied: extractRefs(jobsRaw.applied?.arrayValue),
  confirmed: extractRefs(jobsRaw.confirmed?.arrayValue),
  completed: extractRefs(jobsRaw.completed?.arrayValue),
  declined: extractRefs(jobsRaw.declined?.arrayValue),
};

// ---------- Extract skills ----------
const skills =
  fields.skills?.arrayValue?.values?.map(s => s.stringValue) || [];

// ---------- Extract reviews ----------
const reviews =
  fields.reviews?.arrayValue?.values?.map(r =>
    r.referenceValue
      ? r.referenceValue.split('/').pop()
      : r
  ) || [];

return [{
  profile: {
    id: doc.name.split('/').pop(), // safer than doc.id
    name: fields.name?.stringValue || "",
    email: fields.email?.stringValue || "",
    phone: fields.phone?.stringValue || "",
    bio: fields.bio?.stringValue || "",
    avg_rating: fields.avg_rating?.doubleValue ?? 0,
    profile_img: fields.profile_img?.stringValue || null,
    address,
    skills,
    reviews,
    jobs
  }
}];

// Get all incoming items
const items = $input.all();

return items.map(item => {

  // Safely extract parts text (if present)
  const combinedText = item.json.content?.parts
    ? item.json.content.parts.map(part => part.text || '').join('')
    : '';

  return {
    json: {
      uid: $('Webhook').first().json.body.uid,
      lang: null,
      type: $('Webhook').first().json.body.type,
      msg: combinedText
    }
  };
});

const messages = $json.body.message.messages;
const callId = $json.body.message.call.id;
const lastUser = [...messages].reverse().find(m => m.role === 'user');

return [{
  json: {
    uid: callId,
    msg: lastUser?.content || '',
    lang: 'en-IN',
    type: 'client'
  }
}];
